/**
 * Lucide Icons - Icon Rendering Library
 * Lightweight SVG icon system
 * Full library: https://lucide.dev
 */

const lucide = {
  icons: {
    'chevron-down': '<svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><polyline points="6 9 12 15 18 9"></polyline></svg>',
    'shield-check': '<svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><path d="M12 22s8-4 8-10V5l-8-3-8 3v7c0 6 8 10 8 10z"></path><path d="M9 12l2 2 4-4"></path></svg>',
    'cloud': '<svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><path d="M18 10h-1.26A8 8 0 1 0 9 20h9a5 5 0 0 0 0-10z"></path></svg>',
    'cpu': '<svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><rect x="4" y="4" width="16" height="16" rx="2"/><rect x="9" y="9" width="6" height="6"/><path d="M9 4v-2M9 20v2M15 4v-2M15 20v2M4 9h-2M4 15h-2M20 9h2M20 15h2"/></svg>'
  },
  
  createIcons: function() {
    document.querySelectorAll('[data-lucide]').forEach(el => {
      const iconName = el.getAttribute('data-lucide');
      if (this.icons[iconName]) {
        el.innerHTML = this.icons[iconName];
        el.classList.add('lucide-icon');
      }
    });
  },
  
  addIcon: function(name, svgString) {
    this.icons[name] = svgString;
  }
};

// Export for use
if (typeof window !== 'undefined') {
  window.lucide = lucide;
}
